import React from "react";
import { Routes, Route, Navigate } from "react-router-dom";

import Home from "../pages/Home";
import Login from "../pages/Auth/Login";
import Register from "../pages/Auth/Register";

import VehicleList from "../pages/Vehicles/VehicleList";
import AddVehicle from "../pages/Vehicles/AddVehicle";
import EditVehicle from "../pages/Vehicles/EditVehicle";

import LeadList from "../pages/Leads/LeadList";
import AddLead from "../pages/Leads/AddLead";
import EditLead from "../pages/Leads/EditLead";

import AppointmentList from "../pages/Appointments/AppointmentList";
import AddAppointment from "../pages/Appointments/AddAppointment";
import EditAppointment from "../pages/Appointments/EditAppointment";
import CreateStaff from "../pages/Admin/CreateStaff";

import CustomerBookAppointment from "../pages/Appointments/CustomerBookAppointment";
import MyAppointments from "../pages/Appointments/MyAppointments";
import EditMyAppointment from "../pages/Appointments/EditMyAppointment";

import SaleList from "../pages/Sales/SaleList";
import AddSale from "../pages/Sales/AddSale";
import EditSale from "../pages/Sales/EditSales";

// ✅ change this to the real file you have:
import DocumentList from "../pages/Documents/DocumentList";

import StaffList from "../pages/Admin/StaffList";
import EditStaff from "../pages/Admin/EditStaff";
import AdminDashboard from "../pages/Admin/AdminDashboard";
import RequireAuth from "../components/RequireAuth";
import AdminOrPublicLayout from "../components/AdminOrPublicLayout";
import AdminLayout from "../components/AdminLayout";

//Document
import AddDocument from "../pages/Documents/AddDocument";
import EditDocument from "../pages/Documents/EditDocument";

function AppRoutes() {
  return (
    <Routes>
      <Route path="/" element={<Home />} />

      {/* Vehicle Routes - Staff/Admin/Manager only with sidebar */}
      <Route path="/vehicles/add" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><AddVehicle /></AdminLayout>
      </RequireAuth>} />
      <Route path="/vehicles/edit/:id" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><EditVehicle /></AdminLayout>
      </RequireAuth>} />
      <Route path="/vehicles" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><VehicleList /></AdminLayout>
      </RequireAuth>} />

      {/* Lead Routes - Staff/Admin/Manager only with sidebar */}
      <Route path="/leads" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><LeadList /></AdminLayout>
      </RequireAuth>} />
      <Route path="/leads/add" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><AddLead /></AdminLayout>
      </RequireAuth>} />
      <Route path="/leads/edit/:id" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><EditLead /></AdminLayout>
      </RequireAuth>} />

      {/* Appointment Routes - Staff/Admin/Manager only with sidebar */}
      <Route path="/appointments" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><AppointmentList /></AdminLayout>
      </RequireAuth>} />
      <Route path="/appointments/add" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><AddAppointment /></AdminLayout>
      </RequireAuth>} />
      <Route path="/appointments/edit/:id" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><EditAppointment /></AdminLayout>
      </RequireAuth>} />

      {/* Admin Only Routes - Wrap with AdminLayout */}
      <Route path="/admin/create-staff" element={<RequireAuth roles={["admin"]}>
        <AdminLayout><CreateStaff /></AdminLayout>
      </RequireAuth>} />

      {/* Public Customer Routes - Both customers and staff can book/manage appointments */}
      <Route path="/book-appointment" element={<RequireAuth roles={["user", "admin", "manager", "staff"]}>
        <CustomerBookAppointment />
      </RequireAuth>} />
      <Route path="/my-appointments" element={<RequireAuth roles={["user", "admin", "manager", "staff"]}>
        <MyAppointments />
      </RequireAuth>} />
      <Route path="/edit-my-appointment/:id" element={<RequireAuth roles={["user", "admin", "manager", "staff"]}>
        <EditMyAppointment />
      </RequireAuth>} />

      {/* Sales Routes - Staff/Admin/Manager only with sidebar */}
      <Route path="/sales" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><SaleList /></AdminLayout>
      </RequireAuth>} />
      <Route path="/sales/add" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><AddSale /></AdminLayout>
      </RequireAuth>} />
      <Route path="/sales/edit/:id" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><EditSale /></AdminLayout>
      </RequireAuth>} />

      {/* Document Routes - Staff/Admin/Manager only with sidebar */}
      <Route path="/documents" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><DocumentList /></AdminLayout>
      </RequireAuth>} />
      <Route path="/documents/add" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><AddDocument /></AdminLayout>
      </RequireAuth>} />
      <Route path="/documents/edit/:id" element={<RequireAuth roles={["admin", "manager", "staff"]}>
        <AdminLayout><EditDocument /></AdminLayout>
      </RequireAuth>} />

      {/* Auth Routes - No layout */}
      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />

      {/* Admin Dashboard & Staff Management - Wrap with AdminLayout */}
      <Route path="/admin/dashboard" element={<RequireAuth roles={["admin", "manager"]}>
        <AdminLayout><AdminDashboard /></AdminLayout>
      </RequireAuth>} />
      <Route path="/admin/staff" element={<RequireAuth roles={["admin"]}>
        <AdminLayout><StaffList /></AdminLayout>
      </RequireAuth>} />
      <Route path="/admin/staff/edit/:id" element={<RequireAuth roles={["admin"]}>
        <AdminLayout><EditStaff /></AdminLayout>
      </RequireAuth>} />

      <Route path="*" element={<Navigate to="/" />} />
    </Routes>
  );
}

export default AppRoutes;
